	private static List<String> toSortedList(Set<String> values) {
		if (values == null || values.isEmpty()) {
			return List.of();
		}
		List<String> sorted = new ArrayList<>(values);
		Collections.sort(sorted);
		return List.copyOf(sorted);
	}

	private static double parsePercentageProperty(String property, double defaultPercent) {
		String value = System.getProperty(property);
		if (value == null || value.isBlank()) {
			return defaultPercent / 100.0d;
		}
		try {
			double parsed = Double.parseDouble(value.trim());
			if (parsed < 0.0d) {
				return defaultPercent / 100.0d;
			}
			return parsed / 100.0d;
		} catch (NumberFormatException ignored) {
			return defaultPercent / 100.0d;
		}
	}

	private static double parseDoubleProperty(String property, double defaultValue) {
		String value = System.getProperty(property);
		if (value == null || value.isBlank()) {
			return defaultValue;
		}
		try {
			double parsed = Double.parseDouble(value.trim());
			if (!Double.isFinite(parsed)) {
				return defaultValue;
			}
			return parsed;
		} catch (NumberFormatException ignored) {
			return defaultValue;
		}
	}

	static boolean shouldUseHighUncertaintyGreedyFallback(String plannerUsed, int operandCount, double uncertainty) {
		if (!DP_HIGH_UNCERTAINTY_GREEDY_FALLBACK_ENABLED) {
			return false;
		}
		if (!"dp".equals(plannerUsed) || operandCount < DP_HIGH_UNCERTAINTY_GREEDY_FALLBACK_MIN_OPERANDS) {
			return false;
		}
		return Double.isFinite(uncertainty) && uncertainty >= DP_HIGH_UNCERTAINTY_GREEDY_FALLBACK_MIN_UNCERTAINTY;
	}

	static boolean shouldUseHighUncertaintyLegacyFallback(String plannerUsed, int operandCount, double uncertainty,
			double estimatedCardinality) {
		if (!DP_HIGH_UNCERTAINTY_LEGACY_FALLBACK_ENABLED) {
			return false;
		}
		if (!"dp".equals(plannerUsed)) {
			return false;
		}
		if (!Double.isFinite(uncertainty)) {
			return false;
		}
		double minUncertainty = operandCount * DP_HIGH_UNCERTAINTY_LEGACY_FALLBACK_MIN_UNCERTAINTY_FRACTION;
		if (uncertainty < minUncertainty) {
			return false;
		}
		return operandCount >= DP_HIGH_UNCERTAINTY_LEGACY_FALLBACK_MIN_OPERANDS;
	}

	private static void writePlanTrace(PlanSelectionSnapshot snapshot) {
		String pathValue = System.getProperty(PLAN_TRACE_PATH_PROPERTY);
		if (pathValue == null || pathValue.isBlank()) {
			return;
		}
		Path outputPath = Path.of(pathValue.trim());
		String jsonLine = toJsonLine(snapshot) + System.lineSeparator();
		synchronized (PLAN_TRACE_LOCK) {
			try {
				Path parent = outputPath.getParent();
				if (parent != null) {
					Files.createDirectories(parent);
				}
				Files.writeString(outputPath, jsonLine, StandardCharsets.UTF_8, StandardOpenOption.CREATE,
						StandardOpenOption.APPEND);
			} catch (IOException ignored) {
				// Tracing is best-effort and must never break query execution.
			}
		}
	}

	private static String toJsonLine(PlanSelectionSnapshot snapshot) {
		StringBuilder builder = new StringBuilder(256);
		builder.append('{');
		builder.append("\"timestamp\":\"").append(escapeJson(Instant.now().toString())).append('"');
		builder.append(",\"queryTemplateHash\":\"").append(escapeJson(snapshot.getQueryTemplateHash())).append('"');
		builder.append(",\"selectedCandidate\":").append(snapshot.getSelectedCandidateIndex());
		builder.append(",\"selectedPlanSignature\":\"")
				.append(escapeJson(
						snapshot.getSelectedPlanSignature() == null ? "" : snapshot.getSelectedPlanSignature()))
				.append('"');
		builder.append(",\"reason\":\"").append(escapeJson(snapshot.getReason())).append('"');
		builder.append(",\"plannerUsed\":\"").append(escapeJson(snapshot.getPlannerUsed())).append('"');
		builder.append(",\"stabilityDecision\":\"").append(escapeJson(snapshot.getStabilityDecision())).append('"');
		builder.append(",\"stabilitySource\":\"").append(escapeJson(snapshot.getStabilitySource())).append('"');
		builder.append(",\"rawOrderLabels\":");
		appendStringArray(builder, snapshot.getRawOrderLabels());
		builder.append(",\"finalOrderLabels\":");
		appendStringArray(builder, snapshot.getFinalOrderLabels());
		builder.append(",\"repairApplied\":").append(snapshot.isRepairApplied());
		builder.append(",\"repairBeforeLabels\":");
		appendStringArray(builder, snapshot.getRepairBeforeLabels());
		builder.append(",\"repairAfterLabels\":");
		appendStringArray(builder, snapshot.getRepairAfterLabels());
		builder.append(",\"initiallyBoundVars\":");
		appendStringArray(builder, snapshot.getInitiallyBoundVars());
		builder.append(",\"unsupportedTargets\":");
		appendStringArray(builder, snapshot.getUnsupportedTargets());
		builder.append(",\"rebalanceDiffs\":[");
		List<PlanRewriteDiff> rebalanceDiffs = snapshot.getRebalanceDiffs();
		for (int i = 0; i < rebalanceDiffs.size(); i++) {
			PlanRewriteDiff diff = rebalanceDiffs.get(i);
			if (i > 0) {
				builder.append(',');
			}
			builder.append('{');
			builder.append("\"name\":\"").append(escapeJson(diff.getName())).append('"');
			builder.append(",\"before\":");
			appendStringArray(builder, diff.getBeforeLabels());
			builder.append(",\"after\":");
			appendStringArray(builder, diff.getAfterLabels());
			builder.append('}');
		}
		builder.append(']');
		builder.append(",\"candidates\":[");
		List<JoinPlanCandidate> candidates = snapshot.getCandidates();
		for (int i = 0; i < candidates.size(); i++) {
			JoinPlanCandidate candidate = candidates.get(i);
			if (i > 0) {
				builder.append(',');
			}
			builder.append('{');
			builder.append("\"index\":").append(i);
			builder.append(",\"signature\":\"").append(escapeJson(candidate.getPlanSignature())).append('"');
			builder.append(",\"estimatedTotalCost\":").append(formatNumber(candidate.getEstimatedTotalCost()));
			builder.append(",\"estimatedCardinality\":").append(formatNumber(candidate.getEstimatedCardinality()));
			builder.append(",\"totalUncertainty\":").append(formatNumber(candidate.getTotalUncertainty()));
			builder.append('}');
		}
		builder.append("]}");
		return builder.toString();
	}

	private static void appendStringArray(StringBuilder builder, List<String> values) {
		builder.append('[');
		if (values != null) {
			for (int i = 0; i < values.size(); i++) {
				if (i > 0) {
					builder.append(',');
				}
				builder.append('"').append(escapeJson(values.get(i))).append('"');
			}
		}
		builder.append(']');
	}

	private static String formatNumber(double value) {
		if (!Double.isFinite(value)) {
			return "null";
		}
		return Double.toString(value);
	}

	private static String escapeJson(String value) {
		if (value == null) {
			return "";
		}
		StringBuilder escaped = new StringBuilder(value.length() + 8);
		for (int i = 0; i < value.length(); i++) {
			char c = value.charAt(i);
			switch (c) {
			case '\\':
				escaped.append("\\\\");
				break;
			case '"':
				escaped.append("\\\"");
				break;
			case '\n':
				escaped.append("\\n");
				break;
			case '\r':
				escaped.append("\\r");
				break;
			case '\t':
				escaped.append("\\t");
				break;
			default:
				escaped.append(c);
			}
		}
		return escaped.toString();
	}

